// frontend/src/components/Dashboard/AccountBalance.js
import React from 'react';
import {
  Paper,
  Typography,
  Box,
  Skeleton,
  List,
  ListItem,
  ListItemText,
  Divider,
  Chip,
  useTheme
} from '@mui/material';
import {
  AccountBalance as AccountBalanceIcon,
  TrendingUp,
  TrendingDown,
  Lock,
  LockOpen
} from '@mui/icons-material';

const AccountBalance = ({ balance, loading }) => {
  const theme = useTheme();

  // Debug: Log do balance recebido
  console.log('AccountBalance - balance recebido:', balance);
  console.log('AccountBalance - loading:', loading);

  const formatCurrency = (value, currency = 'USDT') => {
    if (value === null || value === undefined) return `0.00 ${currency}`;
    return `${parseFloat(value).toFixed(2)} ${currency}`;
  };

  const formatNumber = (value) => {
    if (value === null || value === undefined) return '0.00';
    return parseFloat(value).toFixed(2);
  };

  if (loading) {
    return (
      <Paper sx={{ p: 3, height: 400 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
          <Skeleton variant="circular" width={24} height={24} sx={{ mr: 1 }} />
          <Skeleton variant="text" width={150} height={32} />
        </Box>
        <Box sx={{ mb: 2 }}>
          <Skeleton variant="text" width={100} height={20} />
          <Skeleton variant="text" width={120} height={40} />
        </Box>
        <Divider sx={{ my: 2 }} />
        {Array.from({ length: 4 }).map((_, index) => (
          <Box key={index} sx={{ mb: 2 }}>
            <Skeleton variant="text" width={80} height={16} />
            <Skeleton variant="text" width={100} height={24} />
          </Box>
        ))}
      </Paper>
    );
  }

  if (!balance) {
    console.log('AccountBalance - balance é null/undefined');
    return (
      <Paper sx={{ p: 3, height: 400 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 3 }}>
          <AccountBalanceIcon color="primary" />
          Saldo da Conta
        </Typography>
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            height: 300,
            bgcolor: 'background.default',
            borderRadius: 1,
            border: `1px dashed ${theme.palette.divider}`
          }}
        >
          <Typography variant="body1" color="text.secondary">
            Erro ao carregar saldo
          </Typography>
        </Box>
      </Paper>
    );
  }

  // Verificar se balance.data existe e tem api_configured
  const balanceData = balance.data || balance;
  console.log('AccountBalance - balanceData:', balanceData);
  console.log('AccountBalance - api_configured:', balanceData?.api_configured);

  if (!balanceData?.api_configured) {
    console.log('AccountBalance - API não configurada');
    return (
      <Paper sx={{ p: 3, height: 400 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 3 }}>
          <AccountBalanceIcon color="primary" />
          Saldo da Conta
        </Typography>
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            height: 300,
            bgcolor: 'background.default',
            borderRadius: 1,
            border: `1px dashed ${theme.palette.divider}`,
            p: 3
          }}
        >
          <Lock sx={{ fontSize: 48, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h6" color="text.secondary" gutterBottom>
            API Bitget não configurada
          </Typography>
          <Typography variant="body2" color="text.secondary" align="center">
            Configure suas credenciais da API Bitget nas configurações para visualizar o saldo da conta e sincronizar operações.
          </Typography>
        </Box>
      </Paper>
    );
  }

  const totalEquity = parseFloat(balanceData.total_balance || 0);
  const availableBalance = parseFloat(balanceData.available_balance || 0);
  const unrealizedPnl = parseFloat(balanceData.unrealized_pnl || 0);
  const marginRatio = parseFloat(balanceData.margin_ratio || 0);
  const frozenBalance = totalEquity - availableBalance; // Calcular saldo bloqueado
  const apiConfigured = balanceData.api_configured || false;

  const balanceItems = [
    {
      label: 'Patrimônio Total',
      value: formatCurrency(totalEquity),
      description: 'Valor total da conta incluindo posições abertas',
      color: 'primary.main',
      icon: <AccountBalanceIcon />
    },
    {
      label: 'Saldo Disponível',
      value: formatCurrency(availableBalance),
      description: 'Valor disponível para novas operações',
      color: 'success.main',
      icon: <LockOpen />
    },
    {
      label: 'Saldo Bloqueado',
      value: formatCurrency(frozenBalance),
      description: 'Valor usado como margem em posições abertas',
      color: 'warning.main',
      icon: <Lock />
    },
    {
      label: 'PnL Não Realizado',
      value: formatCurrency(unrealizedPnl),
      description: 'Lucro/prejuízo das posições abertas',
      color: unrealizedPnl >= 0 ? 'success.main' : 'error.main',
      icon: unrealizedPnl >= 0 ? <TrendingUp /> : <TrendingDown />
    }
  ];

  const getMarginRiskLevel = (ratio) => {
    if (ratio >= 80) return { color: 'error', label: 'Alto Risco' };
    if (ratio >= 60) return { color: 'warning', label: 'Risco Médio' };
    if (ratio >= 40) return { color: 'info', label: 'Risco Baixo' };
    return { color: 'success', label: 'Seguro' };
  };

  const marginRisk = getMarginRiskLevel(marginRatio);

  return (
    <Paper sx={{ p: 3, height: 400 }}>
      <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 3 }}>
        <AccountBalanceIcon color="primary" />
        Saldo da Conta
      </Typography>

      {/* Patrimônio Total em destaque */}
      <Box sx={{ mb: 3, textAlign: 'center' }}>
        <Typography variant="caption" color="text.secondary">
          Patrimônio Total
        </Typography>
        <Typography
          variant="h4"
          sx={{
            fontWeight: 'bold',
            color: 'primary.main',
            mb: 1
          }}
        >
          {formatCurrency(totalEquity)}
        </Typography>

        {/* Indicador de margem */}
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 1 }}>
          <Typography variant="caption" color="text.secondary">
            Margem:
          </Typography>
          <Chip
            label={`${formatNumber(marginRatio)}%`}
            color={marginRisk.color}
            size="small"
            sx={{ fontWeight: 'bold' }}
          />
          <Typography variant="caption" color={`${marginRisk.color}.main`}>
            {marginRisk.label}
          </Typography>
        </Box>
      </Box>

      <Divider sx={{ mb: 2 }} />

      {/* Lista de saldos */}
      <List dense sx={{ p: 0 }}>
        {balanceItems.slice(1).map((item, index) => (
          <ListItem key={index} sx={{ px: 0, py: 1 }}>
            <Box
              sx={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                width: 32,
                height: 32,
                borderRadius: '50%',
                bgcolor: `${item.color}20`,
                mr: 2
              }}
            >
              {React.cloneElement(item.icon, {
                sx: { color: item.color, fontSize: 16 }
              })}
            </Box>
            <ListItemText
              primary={
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <Typography variant="body2" sx={{ fontWeight: 500 }}>
                    {item.label}
                  </Typography>
                  <Typography
                    variant="body2"
                    sx={{
                      fontWeight: 'bold',
                      color: item.color
                    }}
                  >
                    {item.value}
                  </Typography>
                </Box>
              }
              secondary={
                <Typography variant="caption" color="text.secondary">
                  {item.description}
                </Typography>
              }
            />
          </ListItem>
        ))}
      </List>

      {/* Aviso de margem se necessário */}
      {marginRatio >= 60 && (
        <Box sx={{ mt: 2 }}>
          <Chip
            label="⚠️ Atenção ao nível de margem"
            color="warning"
            size="small"
            sx={{ width: '100%' }}
          />
        </Box>
      )}
    </Paper>
  );
};

export default AccountBalance;
